function calculate1vh() {
  var vh = window.innerHeight * 0.01;
  document.documentElement.style.setProperty('--vh', vh + 'px');
  var sbw = window.innerWidth - document.body.clientWidth;
  document.documentElement.style.setProperty('--sbw', sbw + 'px');
}

function detectLowPC(){
  (!window.isOSX && window.innerWidth>1300 &&  window.innerWidth<1380) ? jQuery('body').addClass('low_pc') : jQuery('body').removeClass('low_pc');
}

function bindPhoneMask($) {
  if (typeof $.fn['inputmask'] != "function") return false;
  $('input[type="tel"]:not(.initialized),input[type="text"][name*=phone]:not(.initialized)').inputmask({
    mask: '+38 (099) 999-99-99',
    showMaskOnHover: false
  }).addClass('initialized');
}


function closeOnOutsideClick(button, target, removeClass) {
  let $button = $(button),
    $target = $(target);
  $(document).mouseup(function(e) {
    if (!$button.is(e.target)) {
      $target.removeClass(removeClass);
    }
  });
}

function pageDisableScroll() {
  if ($('body').hasClass('oxy-modal-active')) {return false}
  var html = $("html"),
    scrollbar = window.innerWidth - document.body.clientWidth;
  scrollbar && html.css('paddingRight', scrollbar + "px");
  html.css("overflow", "hidden");
}

function pageEnableScroll() {
  var html = $("html");
  html.css({ overflow: "visible", paddingRight: 0 });
}

function initToggler($) {
  $('body').on('click', '.toggle-handler', function(e) {
    var $this = $(this),
      target = $this.attr('data-toggle-target') || ($this.is('a') && $this.attr('href').length > 1 ? $this.attr('href') : '') || '',
      _class = $this.attr('data-toggle-class') || 'active',
      $target = target.length ? $(target) : [];
    if (!!$target.length) {
      e.stopPropagation();
      e.stopImmediatePropagation();
      e.preventDefault();
      e.returnValue = false;
      $target.toggleClass(_class).trigger('toggle_class', [_class]);
      return false;
    }
  });
}

/**
 * Current cursor position
 */
var globalMouseX = 'auto',
  globalMouseY = 'auto';

function mousePos($) {
  $('body').mousemove(function(e) {
    globalMouseX = e.clientX;
    globalMouseY = e.clientY;
  });
}

/**
 * Scroll Progress
 */
function addScrollProgress() {
  function scrollProgress() {
    var winScroll = document.body.scrollTop || document.documentElement.scrollTop;
    var height = document.documentElement.scrollHeight - document.documentElement.clientHeight;
    var scrolled = (winScroll / height) * 100;
    document.getElementById("bm-progress-scroll").style.width = scrolled + "%";
  }
  window.onscroll = function() { scrollProgress() };
  scrollProgress();
}


/**
 * Menu
 */
function menuBtn($) {
  $('.menu_btn').on('click', function(event) {
    $(this).toggleClass('menu-active');
    $('.mob_menu, .mob_bar').toggleClass('active');
    if ($('.mob_menu').hasClass('active')) {
      pageDisableScroll();
      let scrollbar = window.innerWidth - document.body.clientWidth;
      $('.menu_btn, .site_chat_btn').css('marginRight', scrollbar + "px");
    }else{
      pageEnableScroll();
      $('.menu_btn, .site_chat_btn').css('marginRight', 0);
    }
  });

  $('.mob_menu__nav li.anchor, .mob_menu__nav li.hide_menu').click(function(event) {
    $('.menu_btn').removeClass('menu-active');
    $('.mob_menu, .mob_bar').removeClass('active');
    pageEnableScroll();
    $('.menu_btn, .site_chat_btn').css('marginRight', 0);
  });
}

function menuHover($) {
  $('.mob_menu__nav ul li').mouseenter(function(event) {
    if ($(window).innerWidth()>1024) {
      if ($(this).hasClass('manager-1')) {
        $('.mob_menu__manager').not('#mob_menu__manager-1').hide();
        $('#mob_menu__manager-1').fadeIn();
      }
      if ($(this).hasClass('manager-2')) {
        $('.mob_menu__manager').not('#mob_menu__manager-2').hide();
        $('#mob_menu__manager-2').fadeIn();
      }
    }
  });

  $('.mob_menu__nav li .bg-1, .mob_menu__nav li .bg-2, .mob_menu__nav li .bg-3').remove();
  $('.mob_menu__nav li').append('<div class="bg-1"></div><div class="bg-2"></div><div class="bg-3"></div>');
}

/**
 * Magnetic Buttons
 **/
function initMagneticButtons($) {

  // Magnetic Buttons
  // Found via: https://codepen.io/tdesero/pen/RmoxQg
  var magnets = document.querySelectorAll('.magnetic');
  var strength = 100;

  // START : If screen is bigger as 540 px do magnetic
  if (window.innerWidth > 768) {
    // Mouse Reset
    magnets.forEach((magnet) => {
      magnet.addEventListener('mousemove', moveMagnet);
      $(this.parentNode).removeClass('not-active');
      magnet.addEventListener('mouseleave', function(event) {
        gsap.to(event.currentTarget, 1.5, {
          x: 0,
          y: 0,
          ease: Elastic.easeOut
        });
        gsap.to($(this).find(".circle_btn-text"), 1.5, {
          x: 0,
          y: 0,
          ease: Elastic.easeOut
        });
      });
    });

    // Mouse move
    function moveMagnet(event) {
      var magnetButton = event.currentTarget;
      var bounding = magnetButton.getBoundingClientRect();
      var magnetsStrength = magnetButton.getAttribute("data-strength");
      var magnetsStrengthText = magnetButton.getAttribute("data-strength-text");

      gsap.to(magnetButton, 1.5, {
        x: (((event.clientX - bounding.left) / magnetButton.offsetWidth) - 0.5) * magnetsStrength,
        y: (((event.clientY - bounding.top) / magnetButton.offsetHeight) - 0.5) * magnetsStrength,
        rotate: "0.001deg",
        ease: Power4.easeOut
      });
      gsap.to($(this).find(".circle_btn-text"), 1.5, {
        x: (((event.clientX - bounding.left) / magnetButton.offsetWidth) - 0.5) * magnetsStrengthText,
        y: (((event.clientY - bounding.top) / magnetButton.offsetHeight) - 0.5) * magnetsStrengthText,
        rotate: "0.001deg",
        ease: Power4.easeOut
      });
    }

  }; // END : If screen is bigger as 768 px do magnetic

  // Mouse Enter
  $('.magnetic-hover').on('mouseenter', function() {
    if ($(this).find(".circle_btn-fill").length && !$(this).closest('.circle_btn').hasClass('active')) {
      gsap.to($(this).find(".circle_btn-fill"), .6, {
        startAt: { y: "76%" },
        y: "0%",
        ease: Power2.easeInOut
      });
    }
    if ($(this).find(".circle_btn-text-inner.change").length && !$(this).closest('.circle_btn').hasClass('active')) {
      gsap.to($(this).find(".circle_btn-text-inner.change"), .1, {
        startAt: { color: "#131313" },
        color: "#FFFFFF",
        ease: Power3.easeIn,
      });
    }
  });

  // Mouse Leave
  $('.magnetic-hover').on('mouseleave', function() {
    if ($(this).find(".circle_btn-fill").length && !$(this).closest('.circle_btn').hasClass('active')) {
      gsap.to($(this).find(".circle_btn-fill"), .6, {
        y: "-76%",
        ease: Power2.easeInOut
      });
    }
    if ($(this).find(".circle_btn-text-inner.change").length && !$(this).closest('.circle_btn').hasClass('active')) {
      gsap.to($(this).find(".circle_btn-text-inner.change"), .1, {
        startAt: { color: "#ffffff" },
        color: "#131313",
        ease: Power3.easeIn,
      });
    }
  });

  // Click btn
  $('.magnetic-click').on('click', function() {
    if ($(this).find(".circle_btn-fill").length) {
      $(this).closest('.circle_btn').toggleClass('active');
    }
  });
  

  let $button = $('.lang_btn, .lang_btn *'),
    $target = $('.lang_btn');
  $(document).mouseup(function(e) {
    if (!$button.is(e.target)) {
      $target.removeClass('active');


    if ($target.find(".circle_btn-fill").length && !$target.hasClass('active')) {
      gsap.to($target.find(".circle_btn-fill"), .6, {
        y: "-76%",
        ease: Power2.easeInOut
      });
    }
    if ($target.find(".circle_btn-text-inner.change").length && !$target.hasClass('active')) {
      gsap.to($target.find(".circle_btn-text-inner.change"), .1, {
        startAt: { color: "#ffffff" },
        color: "#131313",
        ease: Power3.easeIn,
      });
    }

    }
  });

  if (window.pageYOffset >= 500) { $(".circle_btn").addClass('no-border') }
  $(window).scroll(function() {
    var e = $(".circle_btn");
    window.pageYOffset >= 500 ? e.addClass('no-border') : e.removeClass('no-border');
  });
}


