/**
 * Home about cursors
 */
function homeAboutCursors($) {
  let mouseX = 'auto',
    mouseY = 'auto',
    $cursor = $('#home_about__slider_man-cursor');
  let homeAbourSliderCursorLoop = function() {
    $cursor.css({ left: mouseX, top: mouseY });
    requestAnimationFrame(homeAbourSliderCursorLoop);
  };

  if ($(window).innerWidth() >= 1280) {
    $('.click_area_nav-next').mousemove(function(e) {
      mouseX = e.clientX;
      mouseY = e.clientY;
    }).mouseenter(function(e) {
      $cursor.addClass('active');
      $cursor.removeClass('prev');
    }).mouseleave(function(e) {
      $cursor.removeClass('active');
    });
    $('.click_area_nav-prev').mousemove(function(e) {
      mouseX = e.clientX;
      mouseY = e.clientY;
      $('.swiper-active:not(.swiper-slide-active) .home_about__slider_man-itm').removeClass('hover');
      $('.swiper-slide-active .home_about__slider_man-itm').addClass('hover');
    }).mouseenter(function(e) {
      $cursor.addClass('active');
      $cursor.addClass('prev');
      $('.swiper-slide-active .home_about__slider_man-itm').addClass('hover');
    }).mouseleave(function(e) {
      $cursor.removeClass('active');
      $cursor.removeClass('prev');
      $('.swiper-slide-active .home_about__slider_man-itm').removeClass('hover');
    });
    homeAbourSliderCursorLoop();
  }
}

