function codeTextAnimationNew($){

  function getRndInteger(min, max) {
    return Math.floor(Math.random() * (max - min)) + min;
  }

  var codeSymbols = {
      alfabet_0: [' ', 'а', 'б', 'в', 'г', 'д', 'е', 'є', 'ж', 'з', 'и', 'і', 'ї', 'й', 'к', 'л', 'м', 'н', 'о', 'п', 'р', 'с', 'т', 'у', 'ф', 'х', 'ц', 'ч', 'ш', 'щ', 'ь', 'ю', 'я'],
      alfabet: ['&','%','*','@','+','#','~','£','§'],
      code: function(arr, k) {
        let newArr = [];
        for (var i = 0; i < arr.length; i++) {
          if (k>5) {
            k==15 ? newArr[i] = arr[i] : (getRndInteger(0, 2) == 0) ? newArr[i] = arr[i] : newArr[i] = this.alfabet[getRndInteger(0, this.alfabet.length)];
          } else{
            newArr[i] = this.alfabet[getRndInteger(0, this.alfabet.length)];
          }
        }
        return newArr.join('');
      }
    }

  function startCodeListAnim(el) {
    $(el).addClass('active')
    $(el).find('li').each(function(index, el) {
      setTimeout(function() {
        var text = $(el).text(), textArr = text.split(''), k = 0;
        $(el).addClass('active');
        var textInterval = setInterval(function() {
          if (k > 15) {
            clearInterval(textInterval);
          } else{
            $(el).text(codeSymbols.code(textArr, k));
          }
          k += 1;
        }, 50);
      }, 750 + index * 300);
    });
  }

  var controller = new ScrollMagic.Controller();
  $('.home_about__slider_info-slide__list').each(function(index, el) {
    var isAnim = false,
      offset = $(window).innerHeight() * 0.2;
    if ($(window).innerWidth() < 768) { offset = 70; };
    var sceneStart = new ScrollMagic.Scene({
        triggerElement: el,
        triggerHook: "onEnter",
        duration: '70%',
        offset: offset
      })
      .on("enter leave", function(e) {
        (e.type == "enter") && (!isAnim) ? (startCodeListAnim(el), isAnim = true) : true;
      })
      .addTo(controller);
  });

  function startCodeAnim(el) {
    $(el).addClass('active')
    setTimeout(function() {
      var text = $(el).text(), textArr = text.split(''), k = 0;
      var textInterval = setInterval(function() {
        if (k > 15) {
          clearInterval(textInterval);
        } else{
          $(el).text(codeSymbols.code(textArr, k));
        }
        k += 1;
      }, 50);
    }, 75);
  }

  var controller2 = new ScrollMagic.Controller();
  $('.home_works__itm-subtitle, .cases__itm-subtitle').each(function(index, el) {
    var isAnim = false,
      offset = $(window).innerHeight() * 0.2;
    if ($(window).innerWidth() < 768) { offset = 70; };
    var sceneStart = new ScrollMagic.Scene({
        triggerElement: el,
        triggerHook: "onEnter",
        duration: '70%',
        offset: offset
      })
      .on("enter leave", function(e) {
        (e.type == "enter") && (!isAnim) ? (startCodeAnim(el), isAnim = true) : true;
      })
      .addTo(controller2);
  }); 

}



