/**
 * scroll animation template
 */
function uniqScrollAnimations($) {
  var controller = new ScrollMagic.Controller();

  $('[data-anim]').each(function(index, el) {
    offset = $(el).attr('data-anim-offset') ? $(el).attr('data-anim-offset') : $(window).innerHeight() * 0.2;
    if ($(window).innerWidth() < 768) {
      offset = 70;
      $('[data-anim-delay]').each(function(index, el) {
        $(el).attr('data-anim-delay', $(el).data('anim-mob-delay'))
      });
    };

    var sceneStart = new ScrollMagic.Scene({
        triggerElement: el,
        triggerHook: "onEnter",
        duration: '70%',
        offset: offset
      })
      .on("enter leave", function(e) {
        setTimeout(function() {
          e.type == "enter" ? $(el).addClass('active') : true;
        }, $(el).attr('data-anim-delay') ? $(el).attr('data-anim-delay') : 0)
      })
      .addTo(controller);
  });

  var controller2 = new ScrollMagic.Controller();
  $('.home_intro__quote').each(function(index, el) {
    var sceneStart = new ScrollMagic.Scene({
        triggerElement: el,
        triggerHook: "onEnter",
        duration: '70%',
        offset: 0
      })
      .on("enter leave", function(e) {
        if ($(window).innerWidth() >= 1024) {
          e.type == "leave" ? $(el).animate({ 'opacity': 0 }) : $(el).animate({ 'opacity': 1 });
        }
      })
      .addTo(controller2);
  });

}


