function preloaderCounterAnim($){
  var currentStep = 0, preloaderCounter = 0, stack = [];
  $('.persents_wrap__list').attr('data-step', currentStep);
  var preloaderInterval = setInterval(function (){
    preloaderCounter = $('#preloader-counter').html().replace('%', ''),
    newStep = ((preloaderCounter - preloaderCounter % 20) / 20);
    if(newStep != currentStep) {
      currentStep = newStep;
      stack.push(newStep);
    }
    nextStep();
    if (preloaderCounter >= 100 && $('.persents_wrap__list').attr('data-step') == '5'){
      $('.preloader-plus, body').addClass('complete-final').removeClass('complete');
      AOS.refresh();
      clearInterval(preloaderInterval);
    }
  }, 50);

  function nextStep(){
    if (!!stack.length && !$('.persents_wrap__list').hasClass('lock')){
      let step = stack.shift();
      $('.persents_wrap__list').attr('data-step', step);

      $('.persents_wrap__list').addClass('lock');

      setTimeout(function (){
        $('.persents_wrap__list.lock').removeClass('lock');
      }, 400);
    }
  }
}

