function contactPopup($){
  $('.contactPopup-open, .contactPopup-tel-open').on('click', function(event) {
    event.preventDefault();
    $('.popup.active, .contact_popup.active').removeClass('active');
    $(this).hasClass('contactPopup-tel-open') ? $('#contact_popup').removeClass('reverse') : $('#contact_popup').addClass('reverse');
    $('#contact_popup').addClass('active');
    pageDisableScroll();
  });

  function _checkStepValidity(){
    let $tel_step = $('.contact_popup.active .contact_popup__form-step--1'),
    $messengers_step = $('.contact_popup.active .contact_popup__form-step--2'),
    input_val = $tel_step.find('input[type="tel"].dynamic_validate').val();
    if (input_val.indexOf('_') === -1 && input_val != '') {
      $tel_step.addClass('valid');
      $messengers_step.removeClass('disabled');
    } else {
      $tel_step.find('input[type="tel"].dynamic_validate').focus();
      $tel_step.removeClass('valid');
      $messengers_step.addClass('disabled');
    } 
    console.log(input_val);
  }
  $(document).on('input', '.contact_popup__form input[type="tel"].dynamic_validate', _checkStepValidity);

  $('.contact_popup__form-messenger').on('click', function(event) {
    event.preventDefault();
    
    const $btn = $(this);
    const $form = $(this).closest('.contact_popup__form');
    const link = $btn.attr('href') || '';
    
    // Перевіряємо чи є посилання
    if (link === '' || link === '#') return;
    
    // Знаходимо кнопку відправки форми
    const $submitBtn = $form.find('form.wpcf7-form input[type="submit"], form.wpcf7-form .fake_submit');
    
    if ($submitBtn.length > 0) {
      // Відправляємо форму
      $submitBtn.trigger('click');
      
      // Очікуємо відправки форми та переходимо по посиланню
      setTimeout(function() {
        window.open(link, '_blank');
      }, 500);
    } else {
      // Якщо форми немає, просто переходимо по посиланню
      window.open(link, '_blank');
    }

    const wpcf7 = $form.find('form.wpcf7-form');
    wpcf7.on('wpcf7mailsent', function(event) {
      // ID форми CF7
      var formId = event.detail.contactFormId;
      // Сам елемент форми
      var formEl = event.target;

      console.log('Форма CF7 #' + formId + ' успішно відправлена:', formEl);
      setTimeout(function() {
        _checkStepValidity();
      }, 500);
    });
  });
}




