// Глобальный объект для функционала dlpush
var dlpushConfig = {
  prefix: '',
  prefixRules: [{
      'from': 'hdr',
      'to': 'mob_menu_cb',
      'if': '.show-type-menu'
    }
    // Добавляйте новые правила здесь
  ],
  lastSentEvents: {},
  eventCleanupTimer: null,
  pendingEvents: [] // Очередь событий, ожидающих отправки
};

// Функция для очистки устаревших событий
function cleanupOldEvents() {
  const now = Date.now();
  const expireTime = 5000; // 5 секунд

  for (let eventName in dlpushConfig.lastSentEvents) {
    if (now - dlpushConfig.lastSentEvents[eventName] > expireTime) {
      delete dlpushConfig.lastSentEvents[eventName];
    }
  }

  // Если объект пустой, останавливаем таймер
  if (Object.keys(dlpushConfig.lastSentEvents).length === 0) {
    if (dlpushConfig.eventCleanupTimer) {
      clearInterval(dlpushConfig.eventCleanupTimer);
      dlpushConfig.eventCleanupTimer = null;
    }
  }
}

// Функция для запуска периодической очистки
function startEventCleanup() {
  if (!dlpushConfig.eventCleanupTimer) {
    dlpushConfig.eventCleanupTimer = setInterval(cleanupOldEvents, 1000); // Проверяем каждую секунду
  }
}

// Глобальный обработчик для сохранения последнего кликнутого элемента
document.addEventListener('click', function(e) {
  window.lastClickedElement = e.target;
}, true); // Используем capturing phase, чтобы перехватить клик раньше других обработчиков

// Функция для получения данных события
function getDlpushEventData(extended = false, formElement = null) {
  const basicData = {
    page_url: window.location.href,
    user_logged_in: isUserLoggedIn(),
    lang: page_lng,
    referrer: document.referrer || '',
    user_agent: navigator.userAgent || '',
    utm_source: localStorage.getItem('utm_source') || getUrlParameter('utm_source') || '',
    utm_medium: localStorage.getItem('utm_medium') || getUrlParameter('utm_medium') || '',
    utm_campaign: localStorage.getItem('utm_campaign') || getUrlParameter('utm_campaign') || '',
    utm_term: localStorage.getItem('utm_term') || getUrlParameter('utm_term') || '',
    utm_content: localStorage.getItem('utm_content') || getUrlParameter('utm_content') || ''
  };

  if (!extended) {
    return basicData;
  }

  // Расширенные данные для CRM
  const extendedData = {
    ...basicData,
    full_page_url: window.location.href,

    // Данные из URL - всегда проверяем актуальные параметры
    gclid: getUrlParameter('gclid') || localStorage.getItem('gclid') || '',
    fbclid: getUrlParameter('fbclid') || localStorage.getItem('fbclid') || '',
    gbraid: getUrlParameter('gbraid') || localStorage.getItem('gbraid') || '',
    wbraid: getUrlParameter('wbraid') || localStorage.getItem('wbraid') || '',

    // Анализ страницы
    page_section: getPageSection(),
    page_slug: getPageSlug(),

    // Client ID из GA или генерируем свой
    client_id: getClientId(),

    // Маркетинговые поля из localStorage
    clid_source: localStorage.getItem('clid_source') || '',
    clid_userflow: localStorage.getItem('clid_userflow') || '',

    // Поля для отслеживания источников
    has_clid_google: localStorage.getItem('has_clid_google') || '',
    has_clid_facebook: localStorage.getItem('has_clid_facebook') || '',
    has_clid_tiktok: localStorage.getItem('has_clid_tiktok') || '',
    has_clid_telegram: localStorage.getItem('has_clid_telegram') || '',
    has_clid_youtube: localStorage.getItem('has_clid_youtube') || '',
    has_clid_instagram: localStorage.getItem('has_clid_instagram') || '',
    has_clid_linkedin: localStorage.getItem('has_clid_linkedin') || '',

    // Первый и последний источники
    first_clid_source: localStorage.getItem('first_clid_source') || '',
    last_clid_source: localStorage.getItem('last_clid_source') || '',

    // Даты для отслеживания
    first_visit_date: localStorage.getItem('first_visit_date') || '',
    last_visit_date: new Date().toISOString(),

    // Технические параметры
    screen_resolution: window.screen ? `${window.screen.width}x${window.screen.height}` : '',
    viewport_size: `${window.innerWidth}x${window.innerHeight}`,
    timezone: Intl.DateTimeFormat().resolvedOptions().timeZone || '',

    // Параметры сессии
    session_id: getSessionId(),
    visit_count: getVisitCount(),
    page_views_in_session: getPageViewsInSession()
  };

  // Добавляем данные из формы, если форма передана
  if (formElement) {
    const formData = extractFormData(formElement);
    Object.assign(extendedData, formData);
  }

  // Сохраняем актуальные данные в localStorage
  saveMarketingDataToStorage(extendedData);

  return extendedData;
}

// Вспомогательная функция для получения параметра из URL
function getUrlParameter(name) {
  const urlParams = new URLSearchParams(window.location.search);
  return urlParams.get(name) || '';
}

// Функция для определения раздела сайта
function getPageSection() {
  const path = window.location.pathname;

  if (path === '/' || path === '/index.php') return 'home';
//   if (path.includes('/doctors/')) return 'doctors';
//   if (path.includes('/shho-my-likuyemo/')) return 'treatment';
//   if (path.includes('/napryamy/')) return 'consultations';
//   if (path.includes('/methods/')) return 'methods';
//   if (path.includes('/blog/')) return 'blog';
//   if (path.includes('/kontakty/') || path.includes('/pro-spravno/')) return 'info';

  // Попытка определить по первому сегменту
  const segments = path.split('/').filter(segment => segment.length > 0);
  return segments.length > 0 ? segments[0] : 'unknown';
}

// Функция для получения последнего сегмента URL
function getPageSlug() {
  const path = window.location.pathname;
  const segments = path.split('/').filter(segment => segment.length > 0);
  return segments.length > 0 ? segments[segments.length - 1] : '';
}

// Функция для получения Client ID
function getClientId() {
  // Пытаемся получить из Google Analytics
  if (typeof gtag !== 'undefined') {
    try {
      let clientId = '';
      gtag('get', 'GA_MEASUREMENT_ID', 'client_id', (id) => {
        clientId = id;
      });
      if (clientId) return clientId;
    } catch (e) {
      console.warn('Failed to get GA client_id:', e);
    }
  }

  // Проверяем localStorage
  let clientId = localStorage.getItem('client_id');
  if (!clientId) {
    // Генерируем собственный ID
    clientId = 'client_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
    localStorage.setItem('client_id', clientId);
  }

  return clientId;
}

// Функция для извлечения данных из формы
function extractFormData(formElement) {
  const formData = {};

  if (!formElement) return formData;

  // Находим все поля формы
  const inputs = formElement.querySelectorAll('input, textarea, select');

  inputs.forEach(input => {
    const name = input.name;
    const type = input.type;
    const value = input.value;

    // Пропускаем служебные поля
    const serviceFields = [
      '_wpcf7',
      'g-recaptcha-response',
      '_wp',
      'action',
      'acceptance',
      'submit',
      'fphone_countryCode',
      'fphone_phoneCode',
      'client-phone_countryCode',
      'client-phone_phoneCode'
    ];

    if (!name || serviceFields.some(field => name.includes(field))) {
      return;
    }

    // Добавляем префикс ко всем полям
    const processedName = 'form_field_' + name;

    // Обрабатываем разные типы полей
    switch (type) {
      case 'text':
      case 'tel':
      case 'hidden':
      case 'url':
      case 'search':
      case 'number':
      case 'date':
      case 'datetime-local':
      case 'time':
      case 'textarea':
        if (value.trim()) {
          formData[processedName] = value.trim();
        }
        break;

      case 'checkbox':
        // Для checkbox с name собираем значения
        if (input.checked && name) {
          if (formData[processedName]) {
            // Если уже есть значение для этого name, превращаем в массив
            if (Array.isArray(formData[processedName])) {
              formData[processedName].push(input.value || '1');
            } else {
              formData[processedName] = [formData[processedName], input.value || '1'];
            }
          } else {
            formData[processedName] = input.value || '1';
          }
        }
        break;

      case 'radio':
        // Для radio записываем только выбранное значение
        if (input.checked && name) {
          formData[processedName] = input.value;
        }
        break;

      case 'select-one':
        if (value && name) {
          // Для select получаем выбранный text и value
          const selectedOption = input.options[input.selectedIndex];
          formData[processedName] = value;
          if (selectedOption && selectedOption.text !== selectedOption.value) {
            formData[processedName + '_text'] = selectedOption.text;
          }
        }
        break;

      case 'select-multiple':
        if (name) {
          const selectedValues = [];
          const selectedTexts = [];
          for (let i = 0; i < input.options.length; i++) {
            if (input.options[i].selected) {
              selectedValues.push(input.options[i].value);
              if (input.options[i].text !== input.options[i].value) {
                selectedTexts.push(input.options[i].text);
              }
            }
          }
          if (selectedValues.length > 0) {
            formData[processedName] = selectedValues;
            if (selectedTexts.length > 0) {
              formData[processedName + '_text'] = selectedTexts;
            }
          }
        }
        break;
        case 'email':
          if (value.trim()) {
            formData.email = value.trim();
          }
          break;
    }
  });

  // Проверяем, есть ли обязательные поля phone и name
  const hasPhone = Object.keys(formData).some(key =>
    key.includes('form_field_phone') ||
    key.includes('form_field_fphone') ||
    key.includes('form_field_tel') ||
    key.includes('form_field_telephone') ||
    key.includes('form_field_your-phone') ||
    key.includes('form_field_client-phone')
  );

  const hasName = Object.keys(formData).some(key =>
    key.includes('form_field_name') ||
    key.includes('form_field_fname') ||
    key.includes('form_field_fullname') ||
    key.includes('form_field_username') ||
    key.includes('form_field_your-name')
  );

  // Нормализуем названия основных полей
  const phoneFields = ['form_field_phone', 'form_field_fphone', 'form_field_tel', 'form_field_telephone', 'form_field_your-phone'];
  const nameFields = ['form_field_name', 'form_field_fname', 'form_field_fullname', 'form_field_username', 'form_field_your-name'];

  phoneFields.forEach(field => {
    if (formData[field] && !formData.phone) {
      formData.phone = formData[field];
    }
  });

  nameFields.forEach(field => {
    if (formData[field] && !formData.name) {
      formData.name = formData[field];
    }
  });

  // Добавляем метаданные о форме
  formData._form_has_phone = hasPhone ? 'true' : 'false';
  formData._form_has_name = hasName ? 'true' : 'false';
  formData._form_fields_count = Object.keys(formData).filter(key => !key.startsWith('_')).length.toString();

  // Определяем тип формы
  let formType = 'unknown';
  if (hasPhone && hasName) {
    formType = 'full_contact';
  } else if (hasPhone) {
    formType = 'phone_only';
  } else if (hasName) {
    formType = 'name_only';
  }
  formData._form_type = formType;

  return formData;
}

// Функция для проверки авторизации пользователя через куки WordPress
function isUserLoggedIn() {
  // Проверяем наличие WordPress logged-in cookie
  const cookies = document.cookie.split(';');

  for (let cookie of cookies) {
    const trimmedCookie = cookie.trim();
    // WordPress создает куки вида wordpress_logged_in_[hash] для авторизованных пользователей
    if (trimmedCookie.startsWith('wordpress_logged_in_')) {
      return true;
    }
  }

  // Дополнительная проверка через класс body (если тема добавляет этот класс)
  if (document.body.classList.contains('logged-in')) {
    return true;
  }

  return false;
}

// Функция для безопасной отправки события через sendBeacon при необходимости
function sendEventSafely(eventData, eventName, isCritical = false) {
  if (typeof dataLayer !== 'undefined') {
    dataLayer.push(eventData);
    console.log('DataLayer event sent:', eventName);

    // Для критичных событий добавляем в очередь как резерв
    if (isCritical) {
      // Добавляем в очередь критичных событий
      dlpushConfig.pendingEvents.push(eventData);

      // Убираем из очереди через некоторое время (если страница не закрылась)
      setTimeout(function() {
        const index = dlpushConfig.pendingEvents.findIndex(e => e.event === eventName);
        if (index > -1) {
          dlpushConfig.pendingEvents.splice(index, 1);
        }
      }, 2000); // 2 секунды должно хватить для отправки через GA

      // Дополнительная отправка через gtag если доступно
      if (typeof gtag !== 'undefined') {
        const gtagEventName = eventName;
        gtag('event', gtagEventName, {
          'page_url': eventData.page_url,
          'user_logged_in': eventData.user_logged_in,
          'lang': eventData.lang
        });
      }
    }

    return true;
  }
  return false;
}

// Функция для отправки события в dataLayer
function sendDlpushEvent(element, dlpushValue) {
//   if (dlpushConfig.prefix == '') {
    //return;
    // протестируем вариант с префиксом по умолчанию
    //dlpushConfig.prefix = 'unknown';
//   }

  // Проверяем правила замены префикса
  var effectivePrefix = dlpushConfig.prefix;
  for (let rule of dlpushConfig.prefixRules) {
    if (rule.from === dlpushConfig.prefix && rule.if) {
      // Проверяем условие (существование элемента с указанным селектором)
      if (document.querySelector(rule.if)) {
        if (!rule.hasOwnProperty('to') || rule.to == '') {
          return;
        }
        effectivePrefix = rule.to;
        console.log('Prefix replaced by rule:', dlpushConfig.prefix, '->', effectivePrefix, 'due to:', rule.if);
        break;
      }
    }
  }

  if (dlpushValue == 'submit' && dqs('.warn')) {
    return;
  }

  // Ищем data-dlmiddle у элемента и его родителей
  var dlmiddle = '';
  const elementWithMiddle = element.closest('[data-dlmiddle]');
  if (elementWithMiddle) {
    dlmiddle = elementWithMiddle.getAttribute('data-dlmiddle');
  }

  // Формируем название события с эффективным префиксом
  effectivePrefix = effectivePrefix == '' ? '' : effectivePrefix + '_';
  dlmiddle = dlmiddle == '' ? '' : '_' + dlmiddle;
  var eventName = effectivePrefix + dlmiddle + dlpushValue;

  // Проверяем, не было ли это событие отправлено недавно
  const now = Date.now();
  if (dlpushConfig.lastSentEvents[eventName] && (now - dlpushConfig.lastSentEvents[eventName] < 5000)) {
    console.log('Duplicate event prevented:', eventName, 'Last sent:', new Date(dlpushConfig.lastSentEvents[eventName]));
    return;
  }

  // Получаем данные события
  // Для submit событий используем расширенные данные с формой
  const isSubmitEvent = dlpushValue.includes('request') || dlpushValue.includes('requst') || dlpushValue.includes('submit');
  const formElement = isSubmitEvent ? element.closest('form') : null;
  var eventData = getDlpushEventData(isSubmitEvent, formElement);

  // Добавляем название события в данные
  eventData.event = eventName;

  // Определяем критичность события (submit - критичное)
  const isCritical = dlpushValue.includes('request') || dlpushValue.includes('requst') || dlpushValue.includes('submit');

  // Отправляем событие
  if (sendEventSafely(eventData, eventName, isCritical)) {
    // Сохраняем время отправки события
    dlpushConfig.lastSentEvents[eventName] = now;

    // Для submit событий отправляем данные в CRM
    if (isSubmitEvent && formElement) {
      sendToCRM(formElement, eventName, effectivePrefix, dlmiddle, dlpushValue);
    }

    // Запускаем периодическую очистку
    startEventCleanup();
  }
}

// Обработчик кликов по элементам с data-dlpush
document.addEventListener('click', function(e) {
  const element = e.target.closest('[data-dlpush]');
  if (!element) return;

  const dlpushValue = element.getAttribute('data-dlpush');
  if (!dlpushValue) return;

  // Проверяем атрибут data-dlskip
  const dlskipSelector = element.getAttribute('data-dlskip');
  if (dlskipSelector) {
    // Если элемент с указанным селектором существует ДО клика, пропускаем событие
    // (значит виджет уже открыт и мы его закрываем)
    if (document.querySelector(dlskipSelector)) {
      console.log('Event skipped due to data-dlskip (closing):', dlskipSelector);
      return;
    }
  }

  // Ищем data-dlprefix у элемента и его родителей
  const elementWithPrefix = element.closest('[data-dlprefix]');
  if (elementWithPrefix) {
    dlpushConfig.prefix = elementWithPrefix.getAttribute('data-dlprefix');
  }

  if (!dlpushConfig.prefix) {
    //    return;
  }

  // Вызываем функцию отправки события
  // Для submit событий увеличиваем задержку для надежности отправки
  const delay = dlpushValue === 'submit' ? 100 : 1;
  window.setTimeout(function() {
    sendDlpushEvent(element, dlpushValue);
  }, delay);
}, true); // Используем capturing phase

