// Обработчик для обеспечения отправки критичных событий при закрытии страницы
window.addEventListener('beforeunload', function(e) {
  // Если есть критичные события в очереди, пытаемся отправить их
  if (dlpushConfig.pendingEvents.length > 0 && typeof navigator.sendBeacon !== 'undefined') {
    for (let eventData of dlpushConfig.pendingEvents) {
      try {
        // Отправляем через sendBeacon для гарантированной доставки
        const blob = new Blob([JSON.stringify(eventData)], { type: 'application/json' });
        navigator.sendBeacon('/wp-admin/admin-ajax.php?action=log_analytics', blob);
        console.log('Critical event sent via sendBeacon:', eventData.event);
      } catch (error) {
        console.warn('Failed to send critical event via sendBeacon:', error);
      }
    }
    // Очищаем очередь
    dlpushConfig.pendingEvents = [];
  }
});

// Функция для получения Session ID
function getSessionId() {
  let sessionId = sessionStorage.getItem('session_id');
  if (!sessionId) {
    sessionId = 'session_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
    sessionStorage.setItem('session_id', sessionId);
  }
  return sessionId;
}

// Функция для подсчета визитов
function getVisitCount() {
  let visitCount = localStorage.getItem('visit_count');
  if (!visitCount) {
    visitCount = '1';
    localStorage.setItem('visit_count', visitCount);
    localStorage.setItem('first_visit_date', new Date().toISOString());
  } else {
    // Увеличиваем счетчик только если это новая сессия
    if (!sessionStorage.getItem('visit_counted')) {
      visitCount = (parseInt(visitCount) + 1).toString();
      localStorage.setItem('visit_count', visitCount);
      sessionStorage.setItem('visit_counted', 'true');
    }
  }
  return visitCount;
}

// Функция для инициализации счетчика просмотров страниц (вызывается один раз)
function initPageViewsCounter() {
  let pageViews = sessionStorage.getItem('page_views_in_session');
  const lastPageLoad = sessionStorage.getItem('last_page_load_time');
  const currentTime = Date.now().toString();

  // Проверяем, прошло ли достаточно времени с последней загрузки (минимум 1 секунда)
  if (!lastPageLoad || (Date.now() - parseInt(lastPageLoad)) > 1000) {
    if (!pageViews) {
      pageViews = '1';
    } else {
      pageViews = (parseInt(pageViews) + 1).toString();
    }
    sessionStorage.setItem('page_views_in_session', pageViews);
    sessionStorage.setItem('last_page_load_time', currentTime);
  }

  return pageViews;
}

// Функция для получения текущего значения счетчика (без увеличения)
function getPageViewsInSession() {
  return sessionStorage.getItem('page_views_in_session') || '1';
}

// Функция для сохранения маркетинговых данных в localStorage
function saveMarketingDataToStorage(data) {
  // Сохраняем UTM параметры при первом визите
  const utmParams = ['utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content'];
  utmParams.forEach(param => {
    const urlValue = getUrlParameter(param);
    if (urlValue && !localStorage.getItem(param)) {
      localStorage.setItem(param, urlValue);
    }
  });

  // Сохраняем click ID параметры
  const clickIds = ['gclid', 'fbclid', 'gbraid', 'wbraid'];
  clickIds.forEach(param => {
    const urlValue = getUrlParameter(param);
    if (urlValue) {
      localStorage.setItem(param, urlValue);

      // Обновляем источники
      let source = '';
      if (param === 'gclid' || param === 'gbraid' || param === 'wbraid') {
        source = 'google';
        localStorage.setItem('has_clid_google', 'true');
      } else if (param === 'fbclid') {
        source = 'facebook';
        localStorage.setItem('has_clid_facebook', 'true');
      }

      if (source) {
        localStorage.setItem('last_clid_source', source);
        if (!localStorage.getItem('first_clid_source')) {
          localStorage.setItem('first_clid_source', source);
        }

        // Обновляем userflow
        const currentFlow = localStorage.getItem('clid_userflow') || '';
        const newFlow = currentFlow ? `${currentFlow},${source}` : source;
        localStorage.setItem('clid_userflow', newFlow);
        localStorage.setItem('clid_source', source);
      }
    }
  });

  // Определяем источник по UTM
  const utmSource = data.utm_source;
  if (utmSource && !getUrlParameter('gclid') && !getUrlParameter('fbclid')) {
    let detectedSource = '';

    if (utmSource.includes('google') || utmSource.includes('cpc')) {
      detectedSource = 'google';
      localStorage.setItem('has_clid_google', 'true');
    } else if (utmSource.includes('facebook') || utmSource.includes('fb')) {
      detectedSource = 'facebook';
      localStorage.setItem('has_clid_facebook', 'true');
    } else if (utmSource.includes('tiktok')) {
      detectedSource = 'tiktok';
      localStorage.setItem('has_clid_tiktok', 'true');
    } else if (utmSource.includes('telegram')) {
      detectedSource = 'telegram';
      localStorage.setItem('has_clid_telegram', 'true');
    } else if (utmSource.includes('youtube')) {
      detectedSource = 'youtube';
      localStorage.setItem('has_clid_youtube', 'true');
    } else if (utmSource.includes('instagram')) {
      detectedSource = 'instagram';
      localStorage.setItem('has_clid_instagram', 'true');
    } else if (utmSource.includes('linkedin')) {
      detectedSource = 'linkedin';
      localStorage.setItem('has_clid_linkedin', 'true');
    }

    if (detectedSource) {
      localStorage.setItem('last_clid_source', detectedSource);
      if (!localStorage.getItem('first_clid_source')) {
        localStorage.setItem('first_clid_source', detectedSource);
      }
      localStorage.setItem('clid_source', detectedSource);
    }
  }
}

// Функция для инициализации отслеживания маркетинговых параметров
function initMarketingTracking() {
  // Инициализируем базовые счетчики
  getVisitCount();
  initPageViewsCounter(); // Используем новую функцию инициализации

  // Сохраняем маркетинговые параметры из URL
  const currentData = getDlpushEventData(true);

  // Устанавливаем время истечения для localStorage (60 дней)
  const expirationTime = new Date();
  expirationTime.setDate(expirationTime.getDate() + 60);
  localStorage.setItem('marketing_data_expires', expirationTime.toISOString());

  // Проверяем и очищаем устаревшие данные
  cleanupExpiredMarketingData();

  console.log('Marketing tracking initialized:', {
    session_id: getSessionId(),
    visit_count: getVisitCount(),
    page_views: getPageViewsInSession(), // Теперь эта функция только возвращает значение
    utm_source: currentData.utm_source,
    clid_source: currentData.clid_source
  });
}

// Функция для очистки устаревших маркетинговых данных
function cleanupExpiredMarketingData() {
  const expirationDate = localStorage.getItem('marketing_data_expires');
  if (expirationDate && new Date() > new Date(expirationDate)) {
    // Очищаем устаревшие данные, но сохраняем структуру
    const keysToClean = [
      'utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content',
      'gclid', 'fbclid', 'gbraid', 'wbraid',
      'clid_source', 'clid_userflow',
      'has_clid_google', 'has_clid_facebook', 'has_clid_tiktok', 'has_clid_telegram',
      'has_clid_youtube', 'has_clid_instagram', 'has_clid_linkedin',
      'first_clid_source', 'last_clid_source'
    ];

    keysToClean.forEach(key => {
      localStorage.removeItem(key);
    });

    localStorage.removeItem('marketing_data_expires');
    console.log('Expired marketing data cleaned up');
  }
}



// Специальная функция для получения данных для CRM
function getCRMEventData(formElement = null, eventName = null, eventPrefix = null, eventMiddle = null, eventAction = null) {
  const data = getDlpushEventData(true, formElement);

  // Добавляем дополнительные поля специально для CRM
  data.timestamp = new Date().toISOString();
  data.form_submit_time = new Date().toLocaleString('uk-UA', { timeZone: 'Europe/Kiev' });

  // Добавляем информацию о dlpush событии (готовые данные)
  if (eventName) {
    data.dlpush_event_name = eventName;
    data.dlpush_event_prefix = eventPrefix || '';
    data.dlpush_event_middle = eventMiddle || '';
    data.dlpush_event_action = eventAction || '';
  }

  // Добавляем информацию о устройстве
  data.device_type = getDeviceType();
  data.browser_language = navigator.language || navigator.userLanguage || '';
  data.is_mobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);

  // Добавляем информацию о сессии
  data.time_on_page = getTimeOnPage();
  data.scroll_depth = getScrollDepth();

  // Анализ источника трафика
  data.traffic_source_category = getTrafficSourceCategory(data);

  // Дополнительные поля для анализа конверсий
  data.is_returning_visitor = parseInt(data.visit_count) > 1;
  data.pages_viewed_total = data.page_views_in_session;

  return data;
}

// Функция для определения типа устройства
function getDeviceType() {
  const userAgent = navigator.userAgent || '';
  if (/tablet|ipad|playbook|silk/i.test(userAgent)) {
    return 'tablet';
  }
  if (/mobile|iphone|ipod|android|blackberry|opera|mini|windows\sce|palm|smartphone|iemobile/i.test(userAgent)) {
    return 'mobile';
  }
  return 'desktop';
}

// Функция для подсчета времени на странице
function getTimeOnPage() {
  const startTime = sessionStorage.getItem('page_start_time');
  if (!startTime) {
    const now = Date.now();
    sessionStorage.setItem('page_start_time', now.toString());
    return '0';
  }
  return Math.round((Date.now() - parseInt(startTime)) / 60000).toString();
}

// Функция для определения глубины прокрутки
function getScrollDepth() {
  const scrollTop = window.pageYOffset || document.documentElement.scrollTop;
  const documentHeight = document.documentElement.scrollHeight - window.innerHeight;
  const scrollPercent = documentHeight > 0 ? Math.round((scrollTop / documentHeight) * 100) : 0;
  return Math.min(100, Math.max(0, scrollPercent)).toString();
}

// Функция для категоризации источника трафика
function getTrafficSourceCategory(data) {
  const source = data.utm_source || data.clid_source || '';
  const medium = data.utm_medium || '';

  // Платный поиск
  if (data.gclid || source.includes('google') && medium === 'cpc') {
    return 'paid_search_google';
  }

  // Социальные сети
  if (data.fbclid || source.includes('facebook') || source === 'fb') {
    return 'social_facebook';
  }
  if (source.includes('instagram')) return 'social_instagram';
  if (source.includes('tiktok')) return 'social_tiktok';
  if (source.includes('telegram')) return 'social_telegram';
  if (source.includes('youtube')) return 'social_youtube';
  if (source.includes('linkedin')) return 'social_linkedin';

  // Email маркетинг
  if (medium === 'email' || source === 'email') {
    return 'email';
  }

  // Реферальный трафик
  if (medium === 'referral' || data.referrer) {
    return 'referral';
  }

  // Органический поиск
  if (medium === 'organic' || data.referrer.includes('google') || data.referrer.includes('bing')) {
    return 'organic_search';
  }

  // Прямой трафик
  if (medium === '(none)' || !data.referrer) {
    return 'direct';
  }

  return 'other';
}

