// Функция для отправки данных в CRM
function sendToCRM(formElement, eventName, eventPrefix, eventMiddle, eventAction) {
  try {
    // Получаем полные данные для CRM включая dlpush событие
    const crmData = getCRMEventData(formElement, eventName, eventPrefix, eventMiddle, eventAction);

    console.log('Sending data to CRM:', crmData);

    // Отправка в автономный PHP-скрипт (основной метод)
    sendToCRMNoCMS(crmData);

    // Fallback: отправка через WordPress AJAX (если nocms_keycrm.php недоступен)
    // sendToCRMViaWordPress(crmData);

    // Дополнительно: отправка через Google Tag Manager для аналитики
    //    sendToCRMViaGTM(crmData);

  } catch (error) {
    console.error('Error sending data to CRM:', error);
  }
}

// Отправка в автономный PHP-скрипт nocms_keycrm.php
function sendToCRMNoCMS(crmData) {
  const endpoint = '/wp-content/plugins/my-custom-functionality-master/inc/keepingcrm_leads/nocms.php';

  fetch(endpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(crmData)
    })
    .then(response => {
      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }
      return response.json();
    })
    .then(data => {
      console.log('CRM data sent successfully to nocms_keycrm.php:', data);

      // Показываем успешное уведомление в консоли
      if (data.success) {
        console.log(`✅ CRM Lead saved: ${data.details.phones} | Event: ${data.details.event} | Time: ${data.timestamp}`);
      }
    })
    .catch(error => {
      console.error('Failed to send CRM data to nocms_keycrm.php:', error);

      // Fallback: пробуем отправить через WordPress
      //console.log('Trying WordPress fallback...');
      //sendToCRMViaWordPress(crmData);

      // Дополнительный fallback: sendBeacon
      // if (typeof navigator.sendBeacon !== 'undefined') {
      //   const blob = new Blob([JSON.stringify(crmData)], { type: 'application/json' });
      //   const success = navigator.sendBeacon(endpoint, blob);
      //   if (success) {
      //     console.log('CRM data sent via sendBeacon as fallback');
      //   }
      // }
    });
}

// Отправка через WordPress AJAX
function sendToCRMViaWordPress(crmData) {
  const formData = new FormData();
  formData.append('action', 'send_to_crm');
  formData.append('crm_data', JSON.stringify(crmData));

  fetch('/wp-admin/admin-ajax.php', {
      method: 'POST',
      body: formData
    })
    .then(response => response.json())
    .then(data => {
      console.log('CRM data sent successfully:', data);
    })
    .catch(error => {
      console.error('Failed to send CRM data via WordPress:', error);

      // Fallback: попробуем отправить через sendBeacon
      if (typeof navigator.sendBeacon !== 'undefined') {
        const blob = new Blob([JSON.stringify(crmData)], { type: 'application/json' });
        navigator.sendBeacon('/wp-admin/admin-ajax.php?action=send_to_crm', blob);
        console.log('CRM data sent via sendBeacon as fallback');
      }
    });
}

// Отправка через Google Tag Manager
function sendToCRMViaGTM(crmData) {
  if (typeof window.dataLayer !== 'undefined') {
    window.dataLayer.push({
      'event': 'crm_lead_submission',
      'crm_data': crmData
    });
    console.log('CRM data sent to GTM dataLayer');
  } else {
    console.warn('GTM dataLayer not available');
  }
}

