function ecomHeaderAnim($){
  const $percents = $('.header .ecom_divider .text .percents');
  let counter = 0;
  const duration = 1000; // 1 second animation
  const steps = 100;
  const interval = duration / steps;
  
  const timer = setInterval(function() {
    // Format number with leading zeros (3 digits)
    const formattedNumber = String(counter).padStart(3, '0');
    $percents.text(formattedNumber);
    
    counter++;
    
    if (counter > 100) {
      clearInterval(timer);
    }
  }, interval);
}


function ecomSliderSlogan($){
  var ecomSliderSloganSwiper = new Swiper('.ecom_slider__slogan-slider', {
    slidesPerView: 'auto',
    slideClass: 'ecom_slider__slogan-slide',
    wrapperClass: 'ecom_slider__slogan-slider__list',
    speed: 400,
    loop: true,
    centeredSlides: true,
    // loopAdditionalSlides: 1,
    autoplay: {
      delay: 5000,
    }
  });
}

function ecomSliderSloganFrame($){
  let sliderWidth = 0;
  $('.ecom_slider__slogan-slide').each(function(index, el) {
    elWidth = $(el).outerWidth();
    elWidth>sliderWidth ? sliderWidth = elWidth : true;
  });
  $('.ecom_slider__slogan-frame').width(sliderWidth);
  $('.ecom_slider__slogan-blur').css('--slider', sliderWidth + 'px');
}

function headerNav($){
  $('.header__nav-current').on('click', function(event) {
    console.log('dqw');
    event.preventDefault();
    $(this).closest('.header__nav').toggleClass('active');
  });

  closeOnOutsideClick('.header__nav, .header__nav *', '.header__nav', 'active');
}

// --- ecomm-2 (ecom_land) ----------------------------------------------------

// FAQ accordion: open one item at a time
function elandFaqAccordion($) {
  $('.eland_faq__list').on('click', '.eland_faq__q', function() {
    var $itm = $(this).closest('.eland_faq__itm'),
      isActive = $itm.hasClass('active');
    $itm.siblings('.eland_faq__itm').removeClass('active');
    $itm.toggleClass('active', !isActive);
  });
}

// Cases carousel: scroll the track by one card with the prev/next arrows
function elandCasesNav($) {
  $('.eland_cases').each(function() {
    var $sec = $(this),
      track = $sec.find('.eland_cases__track').get(0);
    if (!track) return;
    var getStep = function() {
      var card = $sec.find('.eland_case').get(0);
      return (card ? card.getBoundingClientRect().width : track.clientWidth * 0.8) + 16;
    };
    $sec.find('.eland_cases__arrow--prev').on('click', function() {
      track.scrollBy({ left: -getStep(), behavior: 'smooth' });
    });
    $sec.find('.eland_cases__arrow--next').on('click', function() {
      track.scrollBy({ left: getStep(), behavior: 'smooth' });
    });
  });
}
